-- ======================================================================
-- Part 3: Fix hierarchy DUNS alignment using actual counterparty_hierarchy
-- Sets duns_hq_number and duns_global_ultimate to the parent's own DUNS
-- for all subsidiaries (counterparties whose ultimate_parent_id != self)
-- ======================================================================
UPDATE l2.counterparty c
SET duns_hq_number = p.duns_number,
    duns_global_ultimate = p.duns_number
FROM l2.counterparty_hierarchy h
JOIN l2.counterparty p ON h.ultimate_parent_id = p.counterparty_id
WHERE c.counterparty_id = h.counterparty_id
  AND h.ultimate_parent_id <> h.counterparty_id
  AND c.duns_number IS NOT NULL
  AND p.duns_number IS NOT NULL;
